var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"대관식의 준비가 거의 끝났습니다, 예하.","JPN":"戴冠式の準備が整いました、猊下。","ENG":"The coronation preparations are almost done, Your Eminence.","TWN":"主教，加冕儀式的準備工作已接近尾聲。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"아니, 이젠 성황이라 불러드리면 될까요?","JPN":"いいえ、これからは聖皇とお呼びした方がよろしいでしょうか。","ENG":"Forgive me. Shall I call you pope from now on?","TWN":"不，是不是應該改稱聖皇？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"교단의 방식을 지키거라. 대관식을 치르기 전까지 난 그저 한 사람의 신도일 뿐이니.","JPN":"教団のルールに従え。戴冠式が終わるまで、我はただ一人の信徒に過ぎない。","ENG":"Stick to the Order's doctrine. Before the coronation is complete, I am merely a follower.","TWN":"遵守教團的規矩吧。在正式加冕之前，我仍然只是一名信徒而已。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"선대 성황께서 원정에 실패하여 선종하신 뒤로, 그 빈자리를 채운 예하이십니다.","JPN":"先代の聖王が遠征に失敗しお亡くなりになられたときから、その位置を守ってくださったのは猊下でございます。","ENG":"But after the previous pope passed away due to the failed expedition, it was you who filled that position, Your Eminence.","TWN":"前任聖皇因遠征失敗而善終後，是主教頂替了空缺的位置。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"만민의 믿음으로 예하는 대지에 축복을 내리고, 악을 물리칠 힘을 얻으셨으니, 그들에게는 예하가 곧 신앙이자 교리인 셈이죠.","JPN":"民の信頼によって猊下は大地に祝福を与え、悪を倒せる力を手にしたのです。彼らにとって猊下は信仰であり、教理そのものです。","ENG":"With the faith of all the people, it was you who blessed the earth and gained the strength to repel evil. To them, you are their faith and doctrine, Your Eminence.","TWN":"透過人們的信仰，主教將祝福降臨於大地，並得到了戰勝邪惡的力量，對人們來說您就是信仰和教義。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"의식은 겉치레일 뿐입니다. 이미 모두가 예하를 따르고 있으니까요.","JPN":"儀式は形式に過ぎません。既に皆が猊下に従っております。","ENG":"The coronation is just a formality. Everyone is already following you.","TWN":"儀式只是走個形式而已，大家早已真誠追隨著主教。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"경거망동하는 것은 좋지 않다, 네퀴티아.","JPN":"軽挙妄動するのはよくない、ネキティア。","ENG":"You would be wise to be more discreet, Nequitia.","TWN":"不可輕舉妄動，莉奎蒂亞。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 바라는 것은 엘리시온의 번영일 뿐, 나 자신을 교리보다 위에 둘 생각은 없으니까.","JPN":"我が望むのはエリシオンの繁栄のみ、我を教理より上に置くつもりはないのだ。","ENG":"All I want is prosperity for Elysion. I have no intention of putting myself above the doctrine.","TWN":"我只希望艾利森繁榮昌盛，無意淩駕於教義之上。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"후후, 명심하겠습니다.","JPN":"ふふ、承知いたしました。","ENG":"Fu fuu, of course.","TWN":"呵呵，我會記得的。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"땅이 울리네요. 공기도 조금 차가워졌고요.","JPN":"地響きがします。空気も少し冷たくなっています。","ENG":"The earth is shaking. And the air is getting colder.","TWN":"地面隆隆作響，空氣也變得有些寒冷。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네퀴티아, 길잡이와 함께 전당으로 돌아가라.","JPN":"ネキティア、先に殿堂へ戻れ。","ENG":"Nequitia, return to the palace with your guide.","TWN":"莉奎蒂亞，我會派人把你送回殿堂。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"네? 하지만 전 예하의 대관식에 함께 하고 싶은 걸요.","JPN":"はい？　ですが私は猊下の戴冠式にお伴したいのですが。","ENG":"Pardon? But I wish to attend your coronation, Your Eminence.","TWN":"什麼？但我想參加您的加冕儀式。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"제가 말실수를 한 것 때문에 그러시나요?","JPN":"私が変なことを言ったからでしょうか？","ENG":"Is it because of what I said?","TWN":"是因為我說錯話了嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"지금, 하늘의 태양이 사라졌다.","JPN":"たった今、太陽が消えた。","ENG":"The sun has just disappeared from the sky.","TWN":"太陽從天空中消失了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_BLIND","text":{"KOREA":"태양이… 사라졌다고요?","JPN":"太陽が...…消えたとおっしゃいましたか？","ENG":"The sun is... gone?","TWN":"太陽……消失了？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"틀림없이 역병을 불러들인 마왕의 소행일 것이다.","JPN":"まぎれもなく疫病をばら撒いた魔王の仕業であろう。","ENG":"It must be the doing of the Demon Lord who brought forth the plague.","TWN":"這一定是帶來瘟疫的那魔王所為。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};